30	function computeComponentPremium(items: any[]): number {
31	  const componentCounts: Record<string, number> = {};
32	
33	  for (const item of items) {
34	    if (isComponent(item.type)) {
35	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
36	    }
37	  }
38	
39	  let premium = 0;
40	  for (const count of Object.values(componentCounts)) {
41	    premium += count === COMPONENT_BLOCK_SIZE
42	      ? COMPONENT_BLOCK_PREMIUM
43	      : count * COMPONENT_PREMIUM;
44	  }
45	  return premium;
46	}
47	
48	function computeMainItemPremiums(items: any[]): { base: number; total: number } {
49	  let base = 0;
50	  let total = 0;
51	  for (const item of items) {
52	    if (!isComponent(item.type)) {
53	      const basePremium = MAIN_ITEM_PREMIUMS[item.type];
54	      base += basePremium;
55	      let itemPremium = basePremium;
56	      if (item.cursed) {
57	        itemPremium += basePremium * CURSED_SURCHARGE_RATE;
58	      }
59	      if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
60	        itemPremium += basePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE;
61	      }
62	      total += itemPremium;
63	    }
64	  }
65	  return { base, total };
66	}
