68	const FIRST_INSURANCE_RATE = 0.1;
69	const LOYALTY_DISCOUNT_RATE = 0.2;
70	const LOYALTY_THRESHOLD_YEARS = 2;
71	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
72	
73	function computeInsuranceSum(items: any[]): number {
74	  let sum = 0;
75	  for (const item of items) {
76	    if (isComponent(item.type)) {
77	      sum += COMPONENT_INSURANCE_VALUE;
78	    } else {
79	      sum += INSURANCE_VALUES[item.type];
80	    }
81	  }
82	  return sum;
83	}
