export function processScenario(scenario: any): any {
  const results: any[] = [];
  let quoteCount = 0;
  const policies: Map<number, { items: any[]; remainingCap: number }> = new Map();

  for (let i = 0; i < scenario.steps.length; i++) {
    const step = scenario.steps[i];
    if (step.op === "quote") {
      quoteCount++;
      const componentPremium = computeComponentPremium(step.items);
      const mainItems = computeMainItemPremiums(step.items);
      const totalItemPremium = mainItems.total + componentPremium;
      const policyBase = mainItems.base + componentPremium;
      let policyModifiers = policyBase * FIRST_INSURANCE_RATE;
      if (scenario.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
        policyModifiers -= policyBase * LOYALTY_DISCOUNT_RATE;
      }
      if (quoteCount > 1) {
        policyModifiers -= policyBase * FOLLOW_UP_DISCOUNT_RATE;
      }
      const premium = Math.ceil(totalItemPremium + policyModifiers + PROCESSING_FEE);
      const insuranceSum = computeInsuranceSum(step.items);
      policies.set(i, { items: step.items, remainingCap: insuranceSum * 2 });
      results.push({ premium });
    } else if (step.op === "claim") {
      const policy = policies.get(step.policy)!;
      let totalPayout = 0;
      for (const damage of step.incident.damages) {
        const payout = damage.amount - DEDUCTIBLE;
        totalPayout += Math.max(0, payout);
      }
      totalPayout = Math.min(totalPayout, policy.remainingCap);
      policy.remainingCap -= totalPayout;
      results.push({ payout: Math.floor(totalPayout), remainingCap: policy.remainingCap });
    }
  }

  return { results };
}

